import{_ as d,o as a,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"ランダム画像 API と公開ギャラリー","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Other/random-image-api-and-public-gallery.md","filePath":"ja-JP/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"ja-JP/Other/random-image-api-and-public-gallery.md"};function s(c,t,i,p,n,l){return a(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="ランダム画像-api-と公開ギャラリー" tabindex="-1">ランダム画像 API と公開ギャラリー <a class="header-anchor" href="#ランダム画像-api-と公開ギャラリー" aria-label="Permalink to &quot;ランダム画像 API と公開ギャラリー&quot;">​</a></h1><p>この 2 つの機能はどちらも次の場所で設定します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>システム設定 -&gt; その他の設定</span></span></code></pre></div><h2 id="ランダム画像-api" tabindex="-1">ランダム画像 API <a class="header-anchor" href="#ランダム画像-api" aria-label="Permalink to &quot;ランダム画像 API&quot;">​</a></h2><p>ランダム画像 API は、指定したディレクトリからランダムにファイルを 1 つ返します。サイト背景、アイコンローテーション、外部ページからのランダム画像呼び出しに向いています。</p><p>有効化後は次の URL を利用できます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://あなたのドメイン/random</span></span></code></pre></div><h2 id="api-設定" tabindex="-1">API 設定 <a class="header-anchor" href="#api-設定" aria-label="Permalink to &quot;API 設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>有効</td><td><code>/random</code> を開閉します。無効時はアクセスが拒否されます</td></tr><tr><td>ディレクトリ</td><td>ランダム対象にできるディレクトリを制限します</td></tr><tr><td>呼び出し例</td><td>コピーして使える API URL を生成します</td></tr></tbody></table><p>複数ディレクトリを選択できます。たとえば <code>/landscape/</code> と <code>/portrait/</code> だけを許可すると、それ以外のディレクトリからは返りません。</p><h2 id="主なパラメータ" tabindex="-1">主なパラメータ <a class="header-anchor" href="#主なパラメータ" aria-label="Permalink to &quot;主なパラメータ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>パラメータ</th><th>例</th><th>説明</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>対象ディレクトリ</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td><code>image</code>、<code>video</code>、<code>audio</code> などの種類</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td><code>portrait</code>、<code>landscape</code>、<code>auto</code></td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>空ならリダイレクト、<code>url</code> はテキスト、<code>json</code> は JSON</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td><code>type=url</code> と組み合わせて完全 URL を返します</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>年齢レーティングで絞り込みます</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>指定タグを含むファイルだけにします</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>指定タグを含むファイルを除外します</td></tr></tbody></table><h2 id="戻り値" tabindex="-1">戻り値 <a class="header-anchor" href="#戻り値" aria-label="Permalink to &quot;戻り値&quot;">​</a></h2><p><code>type</code> を指定しない場合、ランダムに選ばれたファイルへ直接リダイレクトします。</p><p><code>type=url</code> は URL 文字列を返します。</p><p><code>type=json</code> はリンク、ファイル ID、ファイル名、種類、タグ、レーティングなどを返します。</p><h2 id="アクセス制御" tabindex="-1">アクセス制御 <a class="header-anchor" href="#アクセス制御" aria-label="Permalink to &quot;アクセス制御&quot;">​</a></h2><p>ランダム画像 API は公開アクセス設定に従います。</p><table tabindex="0"><thead><tr><th>ルール</th><th>影響</th></tr></thead><tbody><tr><td>ディレクトリ制限</td><td>許可されたディレクトリ内だけが対象になります</td></tr><tr><td>ブラックリスト</td><td>ブラックリストのファイルは候補に入りません</td></tr><tr><td>ホワイトリストモード</td><td>公開許可されたファイルだけが返ります</td></tr><tr><td>年齢レーティング</td><td>R12、R16、R18 などを現在のアクセスモードで絞り込みます</td></tr></tbody></table><p>条件に合うファイルがない場合は、該当なしとして返ります。</p><h2 id="公開ギャラリー" tabindex="-1">公開ギャラリー <a class="header-anchor" href="#公開ギャラリー" aria-label="Permalink to &quot;公開ギャラリー&quot;">​</a></h2><p>公開ギャラリーは、訪問者が許可済みディレクトリを読み取り専用で閲覧できるページです。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://あなたのドメイン/browse/ディレクトリ名</span></span></code></pre></div><h2 id="公開ギャラリー設定" tabindex="-1">公開ギャラリー設定 <a class="header-anchor" href="#公開ギャラリー設定" aria-label="Permalink to &quot;公開ギャラリー設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>有効</td><td>公開ギャラリーを開閉します</td></tr><tr><td>画像読み込みモード</td><td>原寸画像またはサムネイルを選びます</td></tr><tr><td>公開ディレクトリ</td><td>訪問者に見せるディレクトリを指定します</td></tr></tbody></table><p>例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>この場合、訪問者は次の URL を開けます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://あなたのドメイン/browse/1</span></span>
<span class="line"><span>https://あなたのドメイン/browse/2</span></span>
<span class="line"><span>https://あなたのドメイン/browse/landscape</span></span>
<span class="line"><span>https://あなたのドメイン/browse/portrait</span></span></code></pre></div><p>未公開のディレクトリへアクセスすると拒否されます。</p><h2 id="ギャラリーでできること" tabindex="-1">ギャラリーでできること <a class="header-anchor" href="#ギャラリーでできること" aria-label="Permalink to &quot;ギャラリーでできること&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>説明</th></tr></thead><tbody><tr><td>ディレクトリ閲覧</td><td>公開ディレクトリ内のファイルとサブディレクトリを表示</td></tr><tr><td>検索</td><td>ファイル名、ID、タグで検索</td></tr><tr><td>種類フィルタ</td><td>画像、動画、音声、その他で絞り込み</td></tr><tr><td>タグフィルタ</td><td>指定タグを含む、または除外する</td></tr><tr><td>向きフィルタ</td><td>横長、縦長などで絞り込み</td></tr><tr><td>リンクコピー</td><td>公開リンクをコピー</td></tr><tr><td>メディアプレビュー</td><td>画像、動画、音声をページ上で確認</td></tr></tbody></table>`,32)])])}const u=d(r,[["render",s]]);export{b as __pageData,u as default};
